(2, 'Turbidity Analysis', 'Measures water clarity by quantifying suspended particles.', 100.0, '#E0F7FA', '#00838F', '#80DEEA', 1),
(3, 'Dissolved Oxygen', 'Measures oxygen content dissolved in water, key for aquatic health.', 50.0, '#E8F5E9', '#2E7D32', '#A5D6A7', 1),
(4, 'Heavy Metals Panel', 'Detects trace concentrations of regulated heavy metals in water.', 250.0, '#FBE9E7', '#D84315', '#FFAB91', 1),
(5, 'Nutrient Analysis', 'Quantifies nitrogen, phosphorus and other nutrient compounds.', 200.0, '#F1F8E9', '#558B2F', '#C5E1A5', 1),
(6, 'Microbial Contamination', 'Screens for coliform bacteria and other microbial indicators.', 100.0, '#FFF3E0', '#EF6C00', '#FFCC80', 1),
(7, 'Water Hardness', 'Measures calcium and magnesium concentration in water samples.', 50.0, '#E8EAF6', '#283593', '#9FA8DA', 1),
(8, 'Chlorine Residual', 'Measures free and total chlorine levels in treated water.', 50.0, '#E0F2F1', '#00695C', '#80CBC4', 1),
(9, 'Total Suspended Solids', 'Measures the dry weight of suspended particles in a water sample.', 250.0, '#FAFAFA', '#424242', '#BDBDBD', 1),
(10, 'Biochemical Oxygen Demand', 'Measures oxygen consumed by microorganisms decomposing organic matter.', 300.0, '#F1F8E9', '#33691E', '#AED581', 1),
(11, 'Chemical Oxygen Demand', 'Measures the oxygen equivalent of organic matter oxidizable by a strong chemical oxidant.', 250.0, '#EDE7F6', '#4527A0', '#B39DDB', 1),
(12, 'Total Dissolved Solids', 'Measures combined dissolved organic and inorganic content in water.', 100.0, '#FFFDE7', '#F9A825', '#FFF59D', 1),
(13, 'Disinfection By-Products', 'Detects trihalomethanes and haloacetic acids formed during chlorination.', 150.0, '#F3E5F5', '#6A1B9A', '#CE93D8', 1),
(14, 'Radionuclide Screening', 'Legacy test for trace radioactive isotopes in drinking water. Retained for records.', 500.0, '#FFEBEE', '#C62828', '#EF9A9A', 0),
