-- ============================================================
-- ARIS LIMS - Full Mock Seed Dataset (Water Sampling)
-- Populates: user, sample_type, test_type, coc, sample,
--            parameter, test, result
--
-- Run AFTER schema.sql, against the aris_lims database:
--   mysql -u root -p aris_lims < seed.sql
--
-- Safe to re-run: clears existing data first, in child-before-
-- parent order (FK checks temporarily disabled during clear).
-- ============================================================

USE `aris_lims`;

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE `result`;
TRUNCATE TABLE `test`;
TRUNCATE TABLE `sample`;
TRUNCATE TABLE `coc`;
TRUNCATE TABLE `parameter`;
TRUNCATE TABLE `test_type`;
TRUNCATE TABLE `sample_type`;
TRUNCATE TABLE `user`;
SET FOREIGN_KEY_CHECKS = 1;

